# ─── Logo helper ─────────────────────────────────────────────────────────────
def load_logo(size):
    img_data = base64.b64decode(LOGO_B64)
    img = Image.open(io.BytesIO(img_data)).convert("RGBA")
    img = img.resize((size, size), Image.LANCZOS)
    return ImageTk.PhotoImage(img)

def make_circle_logo(size):
    """Logo on a circular white background"""
    img_data = base64.b64decode(LOGO_B64)
    cat = Image.open(io.BytesIO(img_data)).convert("RGBA")
    base = Image.new("RGBA", (size, size), (255,255,255,255))
    cat_s = int(size * 0.85)
    cat = cat.resize((cat_s, cat_s), Image.LANCZOS)
    offset = (size - cat_s) // 2
    base.paste(cat, (offset, offset), cat)
    # Circle mask
    mask = Image.new("L", (size, size), 0)
    d = ImageDraw.Draw(mask)
    d.ellipse([0,0,size-1,size-1], fill=255)
    base.putalpha(mask)
    return ImageTk.PhotoImage(base)

def make_rounded_logo(size, radius=8):
    """Logo on white rounded-rect background"""
    img_data = base64.b64decode(LOGO_B64)
    cat = Image.open(io.BytesIO(img_data)).convert("RGBA")
    base = Image.new("RGBA", (size, size), (255,255,255,255))
    cat_s = int(size * 0.85)
    cat = cat.resize((cat_s, cat_s), Image.LANCZOS)
    offset = (size - cat_s) // 2
    base.paste(cat, (offset, offset), cat)
    mask = Image.new("L", (size, size), 0)
    d = ImageDraw.Draw(mask)
    d.rounded_rectangle([0,0,size-1,size-1], radius=radius, fill=255)
    base.putalpha(mask)
    return ImageTk.PhotoImage(base)


# ─── Main App ────────────────────────────────────────────────────────────────
class LumoApp(ctk.CTk):
    def __init__(self):
        super().__init__()

        ctk.set_appearance_mode("dark")
        ctk.set_default_color_theme("dark-blue")

        # Window setup
        self.title("Lumo — Desktop Agent")
        self.geometry("1200x800")
        self.minsize(900, 600)
        self.configure(fg_color=BG3)

        # State
        self.current_model = MODELS[0]
        self.sidebar_open  = True
        self.messages      = []
        self.typing        = False
        self.welcome       = True
        self.convos        = list(DEMO_CONVOS)
        self.active_convo  = None

        # Process management
        self.voice_threads = []  # Track all voice threads
        self.should_stop = False  # Flag to stop all background processes

        # Logo cache
        self._logos = {}

        # Handle window closing - kill all processes
        self.protocol("WM_DELETE_WINDOW", self._on_closing)

        # Build UI
        self._build_titlebar()
        self._build_body()
        self._start_pulse()
        
        # Start background wake word listener
        self._start_voice_listener()

    # ── Logo loader with cache ──
    def get_logo(self, size, shape="round"):
        key = f"{size}_{shape}"
        if key not in self._logos:
            if shape == "round":
                self._logos[key] = make_circle_logo(size)
            else:
                r = max(4, size // 5)
                self._logos[key] = make_rounded_logo(size, r)
        return self._logos[key]

