        self.titlebar.pack(fill="x", side="top")
        self.titlebar.pack_propagate(False)

        # Make window draggable via title bar
        self.titlebar.bind("<ButtonPress-1>",   self._start_drag)
        self.titlebar.bind("<B1-Motion>",       self._do_drag)

        # Traffic lights
        lights = ctk.CTkFrame(self.titlebar, fg_color="transparent")
        lights.pack(side="left", padx=14)
        for color, cmd in [("#ff5f57", self.destroy), ("#ffbd2e", self._minimize), ("#28c840", self._toggle_maximize)]:
            b = tk.Canvas(lights, width=12, height=12, bg=BG3, highlightthickness=0, cursor="hand2")
            b.create_oval(1,1,11,11, fill=color, outline="")
            b.pack(side="left", padx=3)
            b.bind("<Button-1>", lambda e, c=cmd: c())
        self._drag_x = self._drag_y = 0

        # Center title
        center = ctk.CTkFrame(self.titlebar, fg_color="transparent")
        center.place(relx=0.5, rely=0.5, anchor="center")
