    def _build_chat(self):
        self.chat_scroll = ctk.CTkScrollableFrame(
            self.main, fg_color=BG, corner_radius=0,
            scrollbar_button_color=BORDER,
            scrollbar_button_hover_color=BORDER2
        )
        self.chat_scroll.pack(fill="both", expand=True)
        self.chat_inner = self.chat_scroll

        self._show_welcome()

    def _show_welcome(self):
        self._clear_chat()
        self.welcome = True

        container = ctk.CTkFrame(self.chat_inner, fg_color="transparent")
        container.pack(expand=True, pady=(40,32), padx=40)

        # Big logo
        try:
            big = self.get_logo(88, "rect")
            blbl = tk.Label(container, image=big, bg=BG)
            blbl.image = big
            blbl.pack(pady=(0,24))
        except: pass

        ctk.CTkLabel(container, text="What can I help you do?",
                     text_color=WHITE, font=("Inter", 28, "bold")).pack(pady=(0,10))
        ctk.CTkLabel(container,
                     text="Your OS automation agent — use natural language\nto control your system and run commands.",
                     text_color=WHITE, font=("Inter", 14), justify="center").pack(pady=(0,32))

        # Suggestion cards grid
        grid = ctk.CTkFrame(container, fg_color="transparent")
        grid.pack()
        for i, (icon, label, sub) in enumerate(SUGGESTIONS):
            card = ctk.CTkFrame(grid, fg_color=BG2, border_color="#181818",
                                 border_width=1, corner_radius=12, cursor="hand2")
            card.grid(row=i//2, column=i%2, padx=5, pady=5, sticky="nsew")
            grid.grid_columnconfigure(i%2, weight=1)

            icon_box = ctk.CTkFrame(card, fg_color=BORDER, width=36, height=36,
                                     corner_radius=10, border_color=BORDER3, border_width=1)
            icon_box.pack(side="left", padx=(14,10), pady=14)
            icon_box.pack_propagate(False)
            ctk.CTkLabel(icon_box, text=icon, font=("Inter", 17)).pack(expand=True)

            txt = ctk.CTkFrame(card, fg_color="transparent")
            txt.pack(side="left", fill="both", expand=True, pady=14, padx=(0,14))
            ctk.CTkLabel(txt, text=label, text_color=WHITE,
                         font=("Inter", 13, "bold"), anchor="w").pack(fill="x")
            ctk.CTkLabel(txt, text=sub, text_color=WHITE,
                         font=("Inter", 11), anchor="w").pack(fill="x")

            cmd = f"{label} {sub}"
            for w in [card, icon_box, txt]:
                w.bind("<Button-1>", lambda e, c=cmd: self.send(c))
                for child in w.winfo_children():
                    child.bind("<Button-1>", lambda e, c=cmd: self.send(c))

        self._welcome_frame = container

    def _clear_chat(self):
        for w in self.chat_inner.winfo_children():
            w.destroy()

    def _add_message(self, sender, text, timestamp):
        is_user = sender == "user"

        row = ctk.CTkFrame(self.chat_inner, fg_color="transparent")
        row.pack(fill="x", padx=24, pady=6)

        if is_user:
            # Avatar right
            content = ctk.CTkFrame(row, fg_color="transparent")
            content.pack(side="right")
        else:
            content = ctk.CTkFrame(row, fg_color="transparent")
            content.pack(side="left")

        # Avatar
        if is_user:
            av = ctk.CTkFrame(content, fg_color=WHITE, width=30, height=30, corner_radius=15)
            av.pack(side="right", padx=(8,0), anchor="s")
            av.pack_propagate(False)
            ctk.CTkLabel(av, text="U", text_color=BG, font=("Inter", 12, "bold")).pack(expand=True)
        else:
            try:
                al = self.get_logo(30, "round")
                albl = tk.Label(content, image=al, bg=BG)
                albl.image = al
                albl.pack(side="left", padx=(0,8), anchor="s")
            except:
                av = ctk.CTkFrame(content, fg_color=WHITE, width=30, height=30, corner_radius=15)
                av.pack(side="left", padx=(0,8), anchor="s")

        # Bubble column
        bcol = ctk.CTkFrame(content, fg_color="transparent")
        if is_user:
            bcol.pack(side="right")
        else:
            bcol.pack(side="left")

        ctk.CTkLabel(bcol,
                     text="You" if is_user else "Lumo",
                     text_color=WHITE, font=("Inter", 10)).pack(
            anchor="e" if is_user else "w", padx=4)

        bubble = ctk.CTkFrame(
            bcol,
            fg_color=WHITE if is_user else BG4,
            corner_radius=16,
        )
        bubble.pack(anchor="e" if is_user else "w")

        msg_lbl = ctk.CTkLabel(
            bubble, text=text,
            text_color=BG if is_user else WHITE,
            font=("Inter", 13),
            wraplength=460,
            justify="left",
            anchor="w"
        )
        msg_lbl.pack(padx=15, pady=11)

        ctk.CTkLabel(bcol, text=timestamp, text_color=WHITE,
                     font=("Inter", 10)).pack(
            anchor="e" if is_user else "w", padx=4)

        # Scroll to bottom
        self.after(50, lambda: self.chat_scroll._parent_canvas.yview_moveto(1.0))

    def _add_typing_indicator(self):
        self._typing_frame = ctk.CTkFrame(self.chat_inner, fg_color="transparent")
        self._typing_frame.pack(fill="x", padx=24, pady=6, anchor="w")

        row = ctk.CTkFrame(self._typing_frame, fg_color="transparent")
        row.pack(anchor="w")

        try:
            al = self.get_logo(30, "round")
            albl = tk.Label(row, image=al, bg=BG)
            albl.image = al
            albl.pack(side="left", padx=(0,8), anchor="s")
        except: pass

        bubble = ctk.CTkFrame(row, fg_color=BG4, corner_radius=16)
        bubble.pack(side="left", anchor="s")

        dots_frame = ctk.CTkFrame(bubble, fg_color="transparent")
        dots_frame.pack(padx=14, pady=10)
        self._dot_labels = []
        for _ in range(3):
            d = tk.Canvas(dots_frame, width=8, height=8, bg=BG4, highlightthickness=0)
            d.create_oval(1,1,7,7, fill=WHITE, outline="", tags="dot")
            d.pack(side="left", padx=3)
            self._dot_labels.append(d)
        self._dot_state = 0
        self._animate_dots()
        self.after(50, lambda: self.chat_scroll._parent_canvas.yview_moveto(1.0))

    def _animate_dots(self):
        if not self.typing: return
        for i, d in enumerate(self._dot_labels):
            color = WHITE if i == self._dot_state else WHITE
            d.itemconfig("dot", fill=color)
        self._dot_state = (self._dot_state + 1) % 3
        self.after(400, self._animate_dots)

    def _remove_typing(self):
        if hasattr(self, "_typing_frame"):
            self._typing_frame.destroy()

    # ── Input bar ──────────────────────────────────────────────────────────
    def _build_input(self):
        tk.Frame(self.main, bg=BORDER, height=1).pack(fill="x")
        input_area = ctk.CTkFrame(self.main, fg_color=BG, corner_radius=0)
        input_area.pack(fill="x", padx=24, pady=(10,18))

        # Center wrapper
        center = ctk.CTkFrame(input_area, fg_color="transparent")
        center.pack(fill="x")

        self._input_box = ctk.CTkFrame(center, fg_color=BG2, corner_radius=14,
                                        border_color="#141414", border_width=2)
        self._input_box.pack(fill="x")

        self._textarea = ctk.CTkTextbox(
            self._input_box, height=48,
            fg_color="transparent", border_width=0,
            text_color=WHITE, font=("Inter", 14),
            wrap="word",
            activate_scrollbars=False,
        )
        self._textarea.pack(fill="x", padx=16, pady=(10,4))
        self._textarea.insert("0.0", "")
        self._textarea.bind("<KeyPress>", self._on_key)
        self._textarea.bind("<Button-1>", self._on_click)  # Add click handler

        # Placeholder
        self._placeholder_text = "Ask me to do anything...   Shift+Enter for new line"
        self._is_placeholder = False  # Initialize placeholder state
        self._show_placeholder()

        # Bottom row
        btm = ctk.CTkFrame(self._input_box, fg_color="transparent")
        btm.pack(fill="x", padx=10, pady=(0,10))

        self._mic_btn = ctk.CTkButton(btm, text="🎤", width=32, height=32, corner_radius=8,
                      fg_color="transparent", hover_color=BORDER, text_color=WHITE,
                      font=("Inter", 15), command=self.voice_command)
        self._mic_btn.pack(side="left", padx=1)
        ctk.CTkButton(btm, text="📎", width=32, height=32, corner_radius=8,
                      fg_color="transparent", hover_color=BORDER, text_color=WHITE,
                      font=("Inter", 15), command=lambda: None).pack(side="left", padx=1)

        self._send_btn = ctk.CTkButton(
            btm, text="Send", height=36, width=80, corner_radius=9,
            fg_color=WHITE, hover_color="#e0e0e0",
            text_color=BG, font=("Inter", 13, "bold"),
            command=self.send
        )
        self._send_btn.pack(side="right")
        self._update_send_btn()

        # Footer branding
        foot = ctk.CTkFrame(center, fg_color="transparent")
        foot.pack(pady=(10,0))
        try:
            fl = self.get_logo(14, "rect")
            flbl = tk.Label(foot, image=fl, bg=BG)
            flbl.image = fl
            flbl.pack(side="left", padx=(0,6))
        except: pass
        self._foot_lbl = ctk.CTkLabel(
            foot, text=f"Lumo.ai · {self.current_model} · localhost:11434",
            text_color=WHITE, font=("JetBrains Mono", 10)
        )
        self._foot_lbl.pack(side="left")

    # ── Placeholder ────────────────────────────────────────────────────────
    def _show_placeholder(self):
        self._textarea.delete("0.0", "end")
        self._textarea.insert("0.0", self._placeholder_text)
        # Make placeholder text transparent/watermark style
        self._textarea.configure(text_color="#808080")  # Gray color for watermark effect
        self._is_placeholder = True

    def _on_click(self, event):
        # Hide placeholder when clicked
        if self._is_placeholder:
            self._textarea.delete("0.0", "end")
            self._textarea.configure(text_color=WHITE)
            self._is_placeholder = False

    def _on_key(self, event):
        if event.keysym in ("Return",) and not (event.state & 0x1):
            self.send()
            return "break"
        if self._is_placeholder:
            if event.keysym not in ("Shift_L","Shift_R","Control_L","Control_R","Tab"):
                self._textarea.delete("0.0","end")
                self._textarea.configure(text_color=WHITE)
                self._is_placeholder = False
        # Update char count after key
        self.after(10, self._update_char_count)

    def _get_input_text(self):
        if self._is_placeholder:
            return ""
        return self._textarea.get("0.0","end").strip()

    def _update_char_count(self):
        txt = self._get_input_text()
        self._update_send_btn()

    def _update_send_btn(self):
        has_text = bool(self._get_input_text()) and not self.typing
        if has_text:
            self._send_btn.configure(fg_color=WHITE, text_color=BG, state="normal")
            try: self._input_box.configure(border_color=WHITE)
            except: pass
        else:
            self._send_btn.configure(fg_color="transparent", text_color=WHITE, state="disabled")
            try: self._input_box.configure(border_color="#141414")
            except: pass

    # ── Actions ────────────────────────────────────────────────────────────
    def send(self, text=None):
        if self.typing: return
        t = text or self._get_input_text()
        if not t: return

        # Clear input
        self._show_placeholder()
        self._update_send_btn()

        if self.welcome:
            self._clear_chat()
            self.welcome = False

        # Add user bubble
        self.messages.append(("user", t, get_time()))
        self._add_message("user", t, get_time())

        # Update title
        title = t[:34] + ("…" if len(t)>34 else "")
        self._chat_title_lbl.configure(text=title)

        # Add to history
        if t[:26] not in self.convos:
            self.convos.insert(0, t[:26])
            self._add_convo_btn_top(t[:26])

        # Typing
        self.typing = True
        self._add_typing_indicator()
        self._update_send_btn()

        def execute_and_respond():
            try:
                # Execute the actual command and get friendly response
                reply = execute_command(t)
            except Exception as e:
                reply = f"😅 Oops! Something went wrong: {str(e)}\n\nDon't worry, I'm still learning! Try something simpler like 'write a letter' or 'open calculator'! 😊"
            
            time.sleep(1.0)  # Brief delay for realism
            self.after(0, lambda: self._finish_response(reply))

        threading.Thread(target=execute_and_respond, daemon=True).start()

    def _finish_response(self, reply):
        self._remove_typing()
        self.typing = False
        self.messages.append(("ai", reply, get_time()))
        self._add_message("ai", reply, get_time())
        self._update_send_btn()

    def voice_command(self):
        """Handle voice command when microphone button is clicked"""
        def mic_button_clicked():
            if self.should_stop:
                return  # Don't start if app is closing
                
            print("Mic activated")
            # Change mic button to indicate listening
            self.after(0, lambda: self._mic_btn.configure(text="🔴", text_color="#ff4444"))
            
            # Import the working voice function
            from backend import listen_command
            
            try:
                command = listen_command()
                
                if self.should_stop:
                    return  # Stop if app is closing during listening
                    
                # Change mic button back
                self.after(0, lambda: self._mic_btn.configure(text="🎤", text_color=WHITE))
                
                if command:
                    print("Command received:", command)
                    
                    # Add user message
                    self.after(0, lambda: self._add_message("user", command, get_time()))
                    self.after(0, lambda: self._show_placeholder())
                    self.after(0, lambda: self._update_send_btn())
                    
                    # Typing indicator
                    self.typing = True
                    self.after(0, lambda: self._add_typing_indicator())
                    self.after(0, lambda: self._update_send_btn())
                    
                    # Execute command
                    reply = execute_command(command)
                    
                    # Speak response
                    if reply:
                        try:
                            import pyttsx3
                            engine = pyttsx3.init()
                            engine.say(reply)
                            engine.runAndWait()
                        except:
                            pass
                    
                    # Add AI response
                    self.after(0, lambda: self._finish_response(reply))
                else:
                    print("No command received")
                    
            except Exception as e:
                print(f"Voice command error: {e}")
                # Change mic button back
                self.after(0, lambda: self._mic_btn.configure(text="🎤", text_color=WHITE))
        
        # Run voice command in separate thread
        voice_thread = threading.Thread(target=mic_button_clicked, daemon=True)
        voice_thread.start()
        self.voice_threads.append(voice_thread)

    def _on_closing(self):
        """Handle window closing - kill all background processes"""
        print("🛑 Shutting down Lumo...")
        
        # Set stop flag
        self.should_stop = True
        
        # Kill all voice threads
        try:
            # Kill any running calculator processes
            import subprocess
            subprocess.call("taskkill /IM Calculator.exe /F", shell=True)
        except:
            pass
        
        # Kill any Python processes related to voice
        try:
            import psutil
            for proc in psutil.process_iter(['pid', 'name', 'cmdline']):
                try:
                    cmdline = proc.info['cmdline']
                    if cmdline and any('lumo' in str(cmd).lower() for cmd in cmdline):
                        proc.kill()
                except:
                    continue
        except:
            pass
        
        # Destroy the window
        self.destroy()
        print("✅ Lumo shutdown complete")

    def _start_voice_listener(self):
        """Start background wake word listener in a separate thread"""
        if WORKING_VOICE_ENABLED:
            try:
                print("🎤 Starting optimized background voice listener...")
                voice_thread = threading.Thread(target=voice_loop, daemon=True)
                voice_thread.start()
                self.voice_threads.append(voice_thread)
                print("✅ Optimized voice listener started in background")
            except Exception as e:
                print(f"❌ Failed to start voice listener: {e}")
        else:
            print("🔇 Voice system not available")

    def _add_convo_btn_top(self, title):
        btn = ctk.CTkButton(
            self._hist_scroll, text=f"💬  {title}",
            fg_color="transparent", hover_color=BG4,
            text_color=FG5, font=("Inter", 12, "normal"),
            height=34, corner_radius=8, anchor="w",
            command=lambda t=title: self._load_convo(t)
        )
        btn.pack(fill="x", pady=1, before=self._hist_btns[0] if self._hist_btns else None)
        self._hist_btns.insert(0, btn)

    def _load_convo(self, title):
        self._chat_title_lbl.configure(text=title)

    def new_chat(self):
        self.messages = []
        self.typing = False
        self._show_welcome()
        self._chat_title_lbl.configure(text="New Chat")
        self._show_placeholder()
        self._update_send_btn()

    def _select_model(self, model):
        self._model_btns[self.current_model].configure(
            fg_color="transparent", text_color=FG5)
        self.current_model = model
        self._model_btns[model].configure(fg_color=BG4, text_color=WHITE)
        self._topbar_model_lbl.configure(text=model)
        self._model_status_lbl.configure(text=f"ollama · {model}")
        self._footer_model_lbl.configure(text=model)
        self._foot_lbl.configure(text=f"Lumo.ai · {model} · localhost:11434")

    def toggle_sidebar(self):
        if self.sidebar_open:
            self.sidebar.pack_forget()
            self._sb_border.pack_forget()
        else:
            self.sidebar.pack(side="left", fill="y", before=self.main)
            self._sb_border.pack(side="left", fill="y", before=self.main)
        self.sidebar_open = not self.sidebar_open

    # ── Window controls ────────────────────────────────────────────────────
    def _start_drag(self, e):
        self._drag_x = e.x_root - self.winfo_x()
        self._drag_y = e.y_root - self.winfo_y()

    def _do_drag(self, e):
        self.geometry(f"+{e.x_root-self._drag_x}+{e.y_root-self._drag_y}")

    def _minimize(self):
        self.iconify()

    def _toggle_maximize(self):
        if self.state() == "zoomed":
            self.state("normal")
        else:
            self.state("zoomed")

    # ── Pulse animation ────────────────────────────────────────────────────
    def _start_pulse(self):
        self._pulse_state = True
        self._pulse_anim()

    def _pulse_anim(self):
        self._pulse_state = not self._pulse_state
        alpha = 255 if self._pulse_state else 100
        # We can't truly animate canvas colors easily, just toggle
        try:
            self._pulse_canvas.itemconfig("dot", fill=WHITE if self._pulse_state else "#cccccc")
        except: pass
        self.after(1100, self._pulse_anim)


